const body = $input.first().json.body;

// Check required fields
if (!body.from) throw new Error('No sender email provided');
if (!body.sender_ip) throw new Error('No sender IP provided');
if (!body.body) throw new Error('No email body provided');

// Basic email format check
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(body.from)) {
  throw new Error(`Invalid sender email: ${body.from}`);
}

// Validate sender IP format
const ipRegex = /^(\d{1,3}\.){3}\d{1,3}$/;
if (!ipRegex.test(body.sender_ip)) {
  throw new Error(`Invalid sender IP: ${body.sender_ip}`);
}

return $input.all();

const body = $input.first().json.body;
const emailBody = body.body;

// Extract all URLs from email body
const urlRegex = /https?:\/\/[^\s"'<>]+/gi;
const urls = emailBody.match(urlRegex) || [];

// Remove duplicates
const uniqueUrls = [...new Set(urls)];

if (uniqueUrls.length === 0) {
  throw new Error('No URLs found in email body');
}

// Return one item per URL — this is key for the loop
return uniqueUrls.map(url => ({
  json: {
    url,
    from: body.from,
    subject: body.subject,
    sender_ip: body.sender_ip,
    reported_by: body.reported_by,
    timestamp: body.timestamp
  }
}));

return $input.all().map(item => {
  const url = item.json.url;

  try {
    // Parse the URL and get just the domain
    const domain = url
      .replace('https://', '')
      .replace('http://', '')
      .split('/')[0]
      .split('?')[0]
      .toLowerCase();

    return {
      json: {
        ...item.json,
        domain
      }
    };
  } catch(e) {
    return {
      json: {
        ...item.json,
        domain: null
      }
    };
  }
});

// Collect all URL scan results
const allItems = $input.all();

let totalMalicious = 0;
let totalSuspicious = 0;
let maliciousUrls = [];
let scannedDomains = [];

allItems.forEach(item => {
  const stats = item.json.data?.attributes?.last_analysis_stats;
  const domain = item.json.data?.id;

  if (stats) {
    totalMalicious += stats.malicious || 0;
    totalSuspicious += stats.suspicious || 0;
    scannedDomains.push(domain);

    if (stats.malicious > 0 || stats.suspicious > 0) {
      maliciousUrls.push({
        domain,
        malicious: stats.malicious,
        suspicious: stats.suspicious
      });
    }
  }
});

// Get original email data from Webhook node
const emailData = $('Webhook').first().json.body;

return [{
  json: {
    // Email details
    from: emailData.from,
    subject: emailData.subject,
    sender_ip: emailData.sender_ip,
    reported_by: emailData.reported_by,
    timestamp: emailData.timestamp,

    // URL scan summary
    totalUrlsScanned: scannedDomains.length,
    totalMalicious,
    totalSuspicious,
    maliciousUrls,
    scannedDomains,

    // Flag for next step
    hasmaliciousUrls: maliciousUrls.length > 0
  }
}];

const item = $input.first().json;

// Email summary from previous node
const aggregated = $('Code in JavaScript3').first().json;

// AbuseIPDB sender IP data
const abuseScore = item.data.abuseConfidenceScore;
const isTor = item.data.isTor;
const totalReports = item.data.totalReports;
const country = item.data.countryCode;
const isp = item.data.isp;

// URL scan results
const totalMalicious = aggregated.totalMalicious;
const totalSuspicious = aggregated.totalSuspicious;
const totalUrlsScanned = aggregated.totalUrlsScanned;
const maliciousUrls = aggregated.maliciousUrls;

// Suspicious sender domain check
const senderDomain = aggregated.from.split('@')[1];
const suspiciousTlds = ['.ru', '.xyz', '.top', '.tk', '.ml', '.ga'];
const hasSuspiciousTld = suspiciousTlds.some(tld => 
  senderDomain.endsWith(tld)
);

// Phishing risk score
const riskScore = Math.min(100, Math.round(
  (abuseScore * 0.30) +
  (totalMalicious * 15) +
  (totalSuspicious * 8) +
  (isTor ? 20 : 0) +
  (hasSuspiciousTld ? 15 : 0) +
  (totalReports > 50 ? 10 : 0)
));

let severity = "LOW";
if (riskScore >= 80) severity = "CRITICAL";
else if (riskScore >= 60) severity = "HIGH";
else if (riskScore >= 40) severity = "MEDIUM";

return [{
  json: {
    // Email info
    from: aggregated.from,
    subject: aggregated.subject,
    sender_ip: aggregated.sender_ip,
    reported_by: aggregated.reported_by,
    senderDomain,
    hasSuspiciousTld,

    // Risk assessment
    riskScore,
    severity,

    // URL results
    totalUrlsScanned,
    totalMalicious,
    totalSuspicious,
    maliciousUrls,
    scannedDomains: aggregated.scannedDomains,

    // Sender IP intel
    abuseScore,
    isTor,
    totalReports,
    country,
    isp
  }
}];

